function solve(n: number, edges: number[][], k: number): number {
    if (edges.length === 0) {
        return 0;
    }
    edges.sort((a, b) => a[2] - b[2]);
    let low = 0;
    let high = edges[edges.length - 1][2];
    let answer = high;
    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        const dsu = new DSU(n);
        for (const [u, v, w] of edges) {
            if (w <= mid) {
                dsu.union(u, v);
            }
        }
        const components = dsu.count();
        if (components <= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    return answer;
}

