)

type DSU struct {
	parent []int64
	rank   []int64
}

func newDSU(n int64) *DSU {
	parent := make([]int64, n)
	rank := make([]int64, n)
	for i := int64(0); i < n; i++ {
		parent[i] = i
		rank[i] = 1
	}
	return &DSU{parent: parent, rank: rank}
}

func (dsu *DSU) find(x int64) int64 {
	if dsu.parent[x] != x {
		dsu.parent[x] = dsu.find(dsu.parent[x])
	}
	return dsu.parent[x]
}

func (dsu *DSU) union(x, y int64) bool {
	xroot := dsu.find(x)
	yroot := dsu.find(y)
	if xroot == yroot {
		return false
	}
	if dsu.rank[xroot] < dsu.rank[yroot] {
		dsu.parent[xroot] = yroot
	} else {
		dsu.parent[yroot] = xroot
		if dsu.rank[xroot] == dsu.rank[yroot] {
			dsu.rank[xroot]++
		}
	}
	return true
}

func (dsu *DSU) count() int64 {
	roots := make(map[int64]bool)
	for i := int64(0); i < len(dsu.parent); i++ {
		roots[dsu.find(i)] = true
	}
	return int64(len(roots))
}

func solve(n int64, edges [][]int64, k int64) int64 {
	if len(edges) == 0 {
		return 0
	}
	sort.Slice(edges, func(i, j int) bool {
		return edges[i][2] < edges[j][2]
