	parent := make([]int64, n)
	rank := make([]int64, n)
	for i := int64(0); i < n; i++ {
		parent[i] = i
		rank[i] = 0
	}
	return &DSU{parent: parent, rank: rank}
}

func (d *DSU) find(x int64) int64 {
	if d.parent[x] != x {
		d.parent[x] = d.find(d.parent[x])
	}
	return d.parent[x]
}

