	xroot := d.find(x)
	yroot := d.find(y)
	if xroot == yroot {
		return false
	}
	if d.rank[xroot] < d.rank[yroot] {
		d.parent[xroot] = yroot
	} else {
		d.parent[yroot] = xroot
		if d.rank[xroot] == d.rank[yroot] {
			d.rank[xroot]++
		}
	}
	return true
}

func (d *DSU) count() int64 {
	roots := make(map[int64]bool)
	for i := int64(0); i < len(d.parent); i++ {
		roots[d.find(i)] = true
	}
	return int64(len(roots))
}

func solve(n int64, edges [][]int64, k int64) int64 {
